import { describe, expect, it } from "vitest";
import type { ModelMessage } from "ai";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types.js";

// Helper to create a minimal valid ModelMessage
function createModelMessage(overrides: Partial<ModelMessage> = {}): ModelMessage {
  return {
    role: "user",
    content: "test message",
    ...overrides,
  } as ModelMessage;
}

// Helper to create a minimal valid Message
function createMessage(overrides: Partial<Message> = {}): Message {
  return {
    id: "msg-123",
    createdAt: new Date("2024-01-01T00:00:00Z"),
    modelMessage: createModelMessage(),
    ...overrides,
  };
}

// ===========================================
// Message Interface Tests
// ===========================================
describe("Message", () => {
  it("should accept valid Message with all required fields", () => {
    const message: Message = createMessage();
    expect(message.id).toBe("msg-123");
    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.modelMessage).toBeDefined();
  });

  it("should accept Message with optional originalContent", () => {
    const message: Message = {
      ...createMessage(),
      originalContent: "original text before rewrite",
    };
    expect(message.originalContent).toBe("original text before rewrite");
  });

  it("should accept Message without optional fields", () => {
    const message: Message = createMessage();
    expect(message.originalContent).toBeUndefined();
  });

  it("should have correct types for all fields", () => {
    const message: Message = createMessage();
    expect(typeof message.id).toBe("string");
    expect(message.createdAt instanceof Date).toBe(true);
    expect(typeof message.modelMessage).toBe("object");
  });
});

// ===========================================
// CheckpointMessage Interface Tests
// ===========================================
describe("CheckpointMessage", () => {
  function createCheckpointMessage(
    overrides: Partial<CheckpointMessage> = {}
  ): CheckpointMessage {
    return {
      id: "cp-123",
      createdAt: Date.now(),
      isSummary: true,
      message: createModelMessage(),
      ...overrides,
    };
  }

  it("should accept valid CheckpointMessage with all required fields", () => {
    const cp: CheckpointMessage = createCheckpointMessage();
    expect(cp.id).toBe("cp-123");
    expect(typeof cp.createdAt).toBe("number");
    expect(cp.isSummary).toBe(true);
    expect(cp.message).toBeDefined();
  });

  it("should accept CheckpointMessage with optional originalContent", () => {
    const cp: CheckpointMessage = {
      ...createCheckpointMessage(),
      originalContent: "original content",
    };
    expect(cp.originalContent).toBe("original content");
  });

  it("should accept CheckpointMessage with isSummary false", () => {
    const cp: CheckpointMessage = createCheckpointMessage({ isSummary: false });
    expect(cp.isSummary).toBe(false);
  });

  it("createdAt should be a number (Date.now() format)", () => {
    const now = Date.now();
    const cp: CheckpointMessage = createCheckpointMessage({ createdAt: now });
    expect(cp.createdAt).toBe(now);
  });
});

// ===========================================
// SessionMetadata Interface Tests
// ===========================================
describe("SessionMetadata", () => {
  function createSessionMetadata(overrides: Partial<SessionMetadata> = {}): SessionMetadata {
    return {
      sessionId: "session-123",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 100,
      completionTokens: 50,
      summaryMessageId: null,
      ...overrides,
    };
  }

  it("should accept valid SessionMetadata with all required fields", () => {
    const meta: SessionMetadata = createSessionMetadata();
    expect(meta.sessionId).toBe("session-123");
    expect(typeof meta.createdAt).toBe("number");
    expect(typeof meta.updatedAt).toBe("number");
    expect(meta.promptTokens).toBe(100);
    expect(meta.completionTokens).toBe(50);
    expect(meta.summaryMessageId).toBeNull();
  });

  it("should accept summaryMessageId as string when compaction occurred", () => {
    const meta: SessionMetadata = createSessionMetadata({
      summaryMessageId: "summary-msg-456",
    });
    expect(meta.summaryMessageId).toBe("summary-msg-456");
  });

  it("should accept summaryMessageId as null when no compaction", () => {
    const meta: SessionMetadata = createSessionMetadata({ summaryMessageId: null });
    expect(meta.summaryMessageId).toBeNull();
  });

  it("should have correct types for token fields", () => {
    const meta: SessionMetadata = createSessionMetadata();
    expect(typeof meta.promptTokens).toBe("number");
    expect(typeof meta.completionTokens).toBe("number");
  });
});

// ===========================================
// CompactionConfig Interface Tests
// ===========================================
describe("CompactionConfig", () => {
  it("should accept empty CompactionConfig (all fields optional)", () => {
    const config: CompactionConfig = {};
    expect(config).toEqual({});
  });

  it("should accept CompactionConfig with enabled option", () => {
    const config: CompactionConfig = { enabled: true };
    expect(config.enabled).toBe(true);
  });

  it("should accept CompactionConfig with contextLimit", () => {
    const config: CompactionConfig = { contextLimit: 128000 };
    expect(config.contextLimit).toBe(128000);
  });

  it("should accept contextLimit as 0 for unlimited context", () => {
    const config: CompactionConfig = { contextLimit: 0 };
    expect(config.contextLimit).toBe(0);
  });

  it("should accept CompactionConfig with maxTokens", () => {
    const config: CompactionConfig = { maxTokens: 8000 };
    expect(config.maxTokens).toBe(8000);
  });

  it("should accept CompactionConfig with keepRecentTokens", () => {
    const config: CompactionConfig = { keepRecentTokens: 2000 };
    expect(config.keepRecentTokens).toBe(2000);
  });

  it("should accept CompactionConfig with reserveTokens", () => {
    const config: CompactionConfig = { reserveTokens: 2000 };
    expect(config.reserveTokens).toBe(2000);
  });

  it("should accept CompactionConfig with thresholdRatio", () => {
    const config: CompactionConfig = { thresholdRatio: 0.5 };
    expect(config.thresholdRatio).toBe(0.5);
  });

  it("should accept CompactionConfig with speculativeStartRatio", () => {
    const config: CompactionConfig = { speculativeStartRatio: 0.15 };
    expect(config.speculativeStartRatio).toBe(0.15);
  });

  it("should accept CompactionConfig with custom summarizeFn", () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages: ModelMessage[], previousSummary?: string) => {
        return `Summarized ${messages.length} messages. Previous: ${previousSummary ?? "none"}`;
      },
    };
    expect(typeof config.summarizeFn).toBe("function");
  });

  it("should accept full CompactionConfig", () => {
    const config: CompactionConfig = {
      enabled: true,
      contextLimit: 128000,
      maxTokens: 8000,
      keepRecentTokens: 2000,
      reserveTokens: 2000,
      thresholdRatio: 0.5,
      speculativeStartRatio: 0.3,
      summarizeFn: async () => "summary",
    };
    expect(config.enabled).toBe(true);
    expect(config.contextLimit).toBe(128000);
    expect(config.maxTokens).toBe(8000);
    expect(config.keepRecentTokens).toBe(2000);
    expect(config.reserveTokens).toBe(2000);
    expect(config.thresholdRatio).toBe(0.5);
    expect(config.speculativeStartRatio).toBe(0.3);
    expect(typeof config.summarizeFn).toBe("function");
  });
});

// ===========================================
// PruningConfig Interface Tests
// ===========================================
describe("PruningConfig", () => {
  it("should accept empty PruningConfig (all fields optional)", () => {
    const config: PruningConfig = {};
    expect(config).toEqual({});
  });

  it("should accept PruningConfig with enabled option", () => {
    const config: PruningConfig = { enabled: true };
    expect(config.enabled).toBe(true);
  });

  it("should accept PruningConfig with minSavingsTokens", () => {
    const config: PruningConfig = { minSavingsTokens: 200 };
    expect(config.minSavingsTokens).toBe(200);
  });

  it("should accept PruningConfig with protectRecentTokens", () => {
    const config: PruningConfig = { protectRecentTokens: 2000 };
    expect(config.protectRecentTokens).toBe(2000);
  });

  it("should accept PruningConfig with protectedToolNames", () => {
    const config: PruningConfig = {
      protectedToolNames: ["weather", "calculator"],
    };
    expect(config.protectedToolNames).toEqual(["weather", "calculator"]);
  });

  it("should accept PruningConfig with replacementText", () => {
    const config: PruningConfig = {
      replacementText: "[output pruned — too large]",
    };
    expect(config.replacementText).toBe("[output pruned — too large]");
  });

  it("should accept full PruningConfig", () => {
    const config: PruningConfig = {
      enabled: true,
      minSavingsTokens: 500,
      protectRecentTokens: 3000,
      protectedToolNames: ["tool1", "tool2"],
      replacementText: "[pruned]",
    };
    expect(config).toMatchObject({
      enabled: true,
      minSavingsTokens: 500,
      protectRecentTokens: 3000,
      protectedToolNames: ["tool1", "tool2"],
      replacementText: "[pruned]",
    });
  });
});

// ===========================================
// ContinuationVariant Type Tests
// ===========================================
describe("ContinuationVariant", () => {
  it("should accept 'manual' variant", () => {
    const variant: ContinuationVariant = "manual";
    expect(variant).toBe("manual");
  });

  it("should accept 'auto-with-replay' variant", () => {
    const variant: ContinuationVariant = "auto-with-replay";
    expect(variant).toBe("auto-with-replay");
  });

  it("should accept 'tool-loop' variant", () => {
    const variant: ContinuationVariant = "tool-loop";
    expect(variant).toBe("tool-loop");
  });

  it("should only accept valid variants", () => {
    const validVariants: ContinuationVariant[] = ["manual", "auto-with-replay", "tool-loop"];
    validVariants.forEach((v) => {
      expect(["manual", "auto-with-replay", "tool-loop"]).toContain(v);
    });
  });
});

// ===========================================
// CompactionResult Interface Tests
// ===========================================
describe("CompactionResult", () => {
  function createCompactionResult(overrides: Partial<CompactionResult> = {}): CompactionResult {
    return {
      success: true,
      tokensBefore: 10000,
      tokensAfter: 3000,
      ...overrides,
    };
  }

  it("should accept valid CompactionResult with required fields", () => {
    const result: CompactionResult = createCompactionResult();
    expect(result.success).toBe(true);
    expect(result.tokensBefore).toBe(10000);
    expect(result.tokensAfter).toBe(3000);
  });

  it("should accept CompactionResult with optional summaryMessageId", () => {
    const result: CompactionResult = {
      ...createCompactionResult(),
      summaryMessageId: "summary-123",
    };
    expect(result.summaryMessageId).toBe("summary-123");
  });

  it("should accept CompactionResult with optional reason", () => {
    const result: CompactionResult = {
      ...createCompactionResult({ success: false }),
      reason: "Context limit exceeded",
    };
    expect(result.reason).toBe("Context limit exceeded");
  });

  it("should accept CompactionResult with optional continuationVariant", () => {
    const result: CompactionResult = {
      ...createCompactionResult(),
      continuationVariant: "auto-with-replay",
    };
    expect(result.continuationVariant).toBe("auto-with-replay");
  });

  it("should accept failed CompactionResult", () => {
    const result: CompactionResult = createCompactionResult({
      success: false,
      reason: "Failed to summarize",
    });
    expect(result.success).toBe(false);
    expect(result.reason).toBe("Failed to summarize");
  });

  it("should have correct types for token fields", () => {
    const result: CompactionResult = createCompactionResult();
    expect(typeof result.tokensBefore).toBe("number");
    expect(typeof result.tokensAfter).toBe("number");
    expect(typeof result.success).toBe("boolean");
  });
});

// ===========================================
// PreparedCompactionV2 Interface Tests
// ===========================================
describe("PreparedCompactionV2", () => {
  function createPreparedCompactionV2(
    overrides: Partial<PreparedCompactionV2> = {}
  ): PreparedCompactionV2 {
    return {
      baseMessageIds: ["msg-1", "msg-2"],
      revision: 1,
      splitIndex: 5,
      summaryText: "Summary of conversation",
      tokenDelta: -5000,
      ...overrides,
    };
  }

  it("should accept valid PreparedCompactionV2 with required fields", () => {
    const prepared: PreparedCompactionV2 = createPreparedCompactionV2();
    expect(prepared.baseMessageIds).toEqual(["msg-1", "msg-2"]);
    expect(prepared.revision).toBe(1);
    expect(prepared.splitIndex).toBe(5);
    expect(prepared.summaryText).toBe("Summary of conversation");
    expect(prepared.tokenDelta).toBe(-5000);
  });

  it("should accept PreparedCompactionV2 with optional replayMessage", () => {
    const replayMessage: CheckpointMessage = {
      id: "replay-1",
      createdAt: Date.now(),
      isSummary: false,
      message: createModelMessage(),
    };
    const prepared: PreparedCompactionV2 = {
      ...createPreparedCompactionV2(),
      replayMessage,
    };
    expect(prepared.replayMessage).toEqual(replayMessage);
  });

  it("should accept empty baseMessageIds array", () => {
    const prepared: PreparedCompactionV2 = createPreparedCompactionV2({
      baseMessageIds: [],
    });
    expect(prepared.baseMessageIds).toEqual([]);
  });

  it("should have correct types", () => {
    const prepared: PreparedCompactionV2 = createPreparedCompactionV2();
    expect(Array.isArray(prepared.baseMessageIds)).toBe(true);
    expect(typeof prepared.revision).toBe("number");
    expect(typeof prepared.splitIndex).toBe("number");
    expect(typeof prepared.summaryText).toBe("string");
    expect(typeof prepared.tokenDelta).toBe("number");
  });
});

// ===========================================
// ActualTokenUsage Interface Tests
// ===========================================
describe("ActualTokenUsage", () => {
  function createActualTokenUsage(overrides: Partial<ActualTokenUsage> = {}): ActualTokenUsage {
    return {
      promptTokens: 100,
      completionTokens: 50,
      totalTokens: 150,
      updatedAt: new Date("2024-01-01T00:00:00Z"),
      ...overrides,
    };
  }

  it("should accept valid ActualTokenUsage with all required fields", () => {
    const usage: ActualTokenUsage = createActualTokenUsage();
    expect(usage.promptTokens).toBe(100);
    expect(usage.completionTokens).toBe(50);
    expect(usage.totalTokens).toBe(150);
    expect(usage.updatedAt).toBeInstanceOf(Date);
  });

  it("should have correct types for all fields", () => {
    const usage: ActualTokenUsage = createActualTokenUsage();
    expect(typeof usage.promptTokens).toBe("number");
    expect(typeof usage.completionTokens).toBe("number");
    expect(typeof usage.totalTokens).toBe("number");
    expect(usage.updatedAt instanceof Date).toBe(true);
  });

  it("should accept zero values", () => {
