{"path": "packages/harness/src/compaction-types.test.ts", "content": "import { describe, expect, it } from "vitest";
import type { ModelMessage } from "ai";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types.js";

// Helper functions to create test fixtures
function createModelMessage(overrides: Partial<ModelMessage> = {}): ModelMessage {
  return {
    role: "user",
    content: "test message",
    ...overrides,
  } as ModelMessage;
}

function createMessage(overrides: Partial<Message> = {}): Message {
  return {
    id: "msg-1",
    createdAt: new Date("2024-01-01T00:00:00Z"),
    modelMessage: createModelMessage(),
    ...overrides,
  };
}

function createCheckpointMessage(
  overrides: Partial<CheckpointMessage> = {}
): CheckpointMessage {
  return {
    id: "checkpoint-1",
    createdAt: Date.now(),
    isSummary: false,
    message: createModelMessage(),
    ...overrides,
  };
}

describe("compaction-types", () => {
  // ============================================
  // Message Interface Tests
  // ============================================
  describe("Message", () => {
    it("should create a valid Message with all required fields", () => {
      const message: Message = createMessage();

      expect(message.id).toBe("msg-1");
      expect(message.createdAt).toBeInstanceOf(Date);
      expect(message.modelMessage).toBeDefined();
      expect(message.modelMessage.role).toBe("user");
    });

    it("should allow optional originalContent field", () => {
      const messageWithContent: Message = createMessage({
        originalContent: "original text",
      });
      const messageWithoutContent: Message = createMessage();

      expect(messageWithContent.originalContent).toBe("original text");
      expect(messageWithoutContent.originalContent).toBeUndefined();
    });

    it("should accept different ModelMessage types", () => {
      const userMessage: Message = createMessage({
        modelMessage: createModelMessage({ role: "user", content: "user input" }),
      });
      const assistantMessage: Message = createMessage({
        modelMessage: createModelMessage({ role: "assistant", content: "assistant response" }),
      });

      expect(userMessage.modelMessage.role).toBe("user");
      expect(assistantMessage.modelMessage.role).toBe("assistant");
    });

    it("should accept Date instance for createdAt", () => {
      const now = new Date();
      const message: Message = createMessage({ createdAt: now });

      expect(message.createdAt).toBe(now);
      expect(message.createdAt).toBeInstanceOf(Date);
    });
  });

  // ============================================
  // CheckpointMessage Interface Tests
  // ============================================
  describe("CheckpointMessage", () => {
    it("should create a valid CheckpointMessage with all required fields", () => {
      const checkpoint: CheckpointMessage = createCheckpointMessage();

      expect(checkpoint.id).toBe("checkpoint-1");
      expect(typeof checkpoint.createdAt).toBe("number");
      expect(checkpoint.isSummary).toBe(false);
      expect(checkpoint.message).toBeDefined();
    });

    it("should allow optional originalContent field", () => {
      const checkpointWithContent: CheckpointMessage = createCheckpointMessage({
        originalContent: "original",
      });
      const checkpointWithoutContent: CheckpointMessage = createCheckpointMessage();

      expect(checkpointWithContent.originalContent).toBe("original");
      expect(checkpointWithoutContent.originalContent).toBeUndefined();
    });

    it("should use number timestamp for createdAt (Date.now format)", () => {
      const timestamp = 1704067200000; // 2024-01-01
      const checkpoint: CheckpointMessage = createCheckpointMessage({
        createdAt: timestamp,
      });

      expect(typeof checkpoint.createdAt).toBe("number");
      expect(checkpoint.createdAt).toBe(timestamp);
    });

    it("should distinguish summary messages with isSummary flag", () => {
      const summaryCheckpoint: CheckpointMessage = createCheckpointMessage({
        isSummary: true,
      });
      const normalCheckpoint: CheckpointMessage = createCheckpointMessage({
        isSummary: false,
      });

      expect(summaryCheckpoint.isSummary).toBe(true);
      expect(normalCheckpoint.isSummary).toBe(false);
    });
  });

  // ============================================
  // SessionMetadata Interface Tests
  // ============================================
  describe("SessionMetadata", () => {
    it("should create a valid SessionMetadata with all required fields", () => {
      const metadata: SessionMetadata = {
        sessionId: "session-1",
        createdAt: Date.now(),
        updatedAt: Date.now(),
        promptTokens: 100,
        completionTokens: 50,
        summaryMessageId: null,
      };

      expect(metadata.sessionId).toBe("session-1");
      expect(typeof metadata.createdAt).toBe("number");
      expect(typeof metadata.updatedAt).toBe("number");
      expect(metadata.promptTokens).toBe(100);
      expect(metadata.completionTokens).toBe(50);
    });

    it("should accept string or null for summaryMessageId", () => {
      const noSummary: SessionMetadata = {
        sessionId: "session-1",
        createdAt: Date.now(),
        updatedAt: Date.now(),
        promptTokens: 100,
        completionTokens: 50,
        summaryMessageId: null,
      };
      const withSummary: SessionMetadata = {
        sessionId: "session-2",
        createdAt: Date.now(),
        updatedAt: Date.now(),
        promptTokens: 200,
        completionTokens: 100,
        summaryMessageId: "summary-msg-1",
      };

      expect(noSummary.summaryMessageId).toBeNull();
      expect(withSummary.summaryMessageId).toBe("summary-msg-1");
    });

    it("should track token counts correctly", () => {
      const metadata: SessionMetadata = {
        sessionId: "session-1",
        createdAt: Date.now(),
        updatedAt: Date.now(),
        promptTokens: 1500,
        completionTokens: 750,
        summaryMessageId: null,
      };

      expect(metadata.promptTokens).toBe(1500);
      expect(metadata.completionTokens).toBe(750);
    });
  });

  // ============================================
  // CompactionConfig Interface Tests
  // ============================================
  describe("CompactionConfig", () => {
    it("should create an empty CompactionConfig (all fields optional)", () => {
      const config: CompactionConfig = {};

      expect(config.enabled).toBeUndefined();
      expect(config.contextLimit).toBeUndefined();
      expect(config.maxTokens).toBeUndefined();
      expect(config.thresholdRatio).toBeUndefined();
      expect(config.keepRecentTokens).toBeUndefined();
      expect(config.reserveTokens).toBeUndefined();
      expect(config.speculativeStartRatio).toBeUndefined();
      expect(config.summarizeFn).toBeUndefined();
    });

    it("should allow setting enabled field", () => {
      const enabledConfig: CompactionConfig = { enabled: true };
      const disabledConfig: CompactionConfig = { enabled: false };

      expect(enabledConfig.enabled).toBe(true);
      expect(disabledConfig.enabled).toBe(false);
    });

    it("should allow setting contextLimit (0 means unlimited)", () => {
      const unlimitedConfig: CompactionConfig = { contextLimit: 0 };
      const limitedConfig: CompactionConfig = { contextLimit: 128000 };

      expect(unlimitedConfig.contextLimit).toBe(0);
      expect(limitedConfig.contextLimit).toBe(128000);
    });

    it("should allow setting maxTokens", () => {
      const config: CompactionConfig = { maxTokens: 8000 };

      expect(config.maxTokens).toBe(8000);
    });

    it("should allow setting thresholdRatio (0-1 range)", () => {
      const config: CompactionConfig = { thresholdRatio: 0.5 };

      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should allow setting keepRecentTokens", () => {
      const config: CompactionConfig = { keepRecentTokens: 2000 };

      expect(config.keepRecentTokens).toBe(2000);
    });

    it("should allow setting reserveTokens", () => {
      const config: CompactionConfig = { reserveTokens: 2000 };

      expect(config.reserveTokens).toBe(2000);
    });

    it("should allow setting speculativeStartRatio (0.15-0.95 range)", () => {
      const minRatio: CompactionConfig = { speculativeStartRatio: 0.15 };
      const maxRatio: CompactionConfig = { speculativeStartRatio: 0.95 };

      expect(minRatio.speculativeStartRatio).toBe(0.15);
      expect(maxRatio.speculativeStartRatio).toBe(0.95);
    });

    it("should allow setting summarizeFn as a function", async () => {
      const summarizeFn = async (messages: ModelMessage[], previousSummary?: string) => {
        return `Summary of ${messages.length} messages. Previous: ${previousSummary ?? "none"}`;
      };

      const config: CompactionConfig = { summarizeFn };

      expect(typeof config.summarizeFn).toBe("function");
      const result = await config.summarizeFn!([createModelMessage()]);
      expect(result).toContain("Summary of 1 messages");
    });

    it("should allow all fields to be set together", () => {
      const config: CompactionConfig = {
        enabled: true,
        contextLimit: 128000,
        maxTokens: 10000,
        thresholdRatio: 0.75,
        keepRecentTokens: 2000,
        reserveTokens: 1500,
        speculativeStartRatio: 0.8,
        summarizeFn: async () => "summary",
      };

      expect(config.enabled).toBe(true);
      expect(config.contextLimit).toBe(128000);
      expect(config.maxTokens).toBe(10000);
      expect(config.thresholdRatio).toBe(0.75);
      expect(config.keepRecentTokens).toBe(2000);
      expect(config.reserveTokens).toBe(1500);
      expect(config.speculativeStartRatio).toBe(0.8);
      expect(typeof config.summarizeFn).toBe("function");
    });
  });

  // ============================================
  // PruningConfig Interface Tests
  // ============================================
  describe("PruningConfig", () => {
    it("should create an empty PruningConfig (all fields optional)", () => {
      const config: PruningConfig = {};

      expect(config.enabled).toBeUndefined();
      expect(config.minSavingsTokens).toBeUndefined();
      expect(config.protectedToolNames).toBeUndefined();
      expect(config.protectRecentTokens).toBeUndefined();
      expect(config.replacementText).toBeUndefined();
    });

    it("should allow setting enabled field", () => {
      const enabledConfig: PruningConfig = { enabled: true };
      const disabledConfig: PruningConfig = { enabled: false };

      expect(enabledConfig.enabled).toBe(true);
      expect(disabledConfig.enabled).toBe(false);
    });

    it("should allow setting minSavingsTokens", () => {
      const config: PruningConfig = { minSavingsTokens: 200 };

      expect(config.minSavingsTokens).toBe(200);
    });

    it("should allow setting protectedToolNames as an array", () => {
      const config: PruningConfig = {
        protectedToolNames: ["read_file", "write_file", "shell_execute"],
      };

      expect(config.protectedToolNames).toHaveLength(3);
      expect(config.protectedToolNames).toContain("read_file");
    });

    it("should allow empty protectedToolNames array", () => {
      const config: PruningConfig = { protectedToolNames: [] };

      expect(config.protectedToolNames).toEqual([]);
    });

    it("should allow setting protectRecentTokens", () => {
      const config: PruningConfig = { protectRecentTokens: 2000 };

      expect(config.protectRecentTokens).toBe(2000);
    });

    it("should allow setting replacementText", () => {
      const config: PruningConfig = {
        replacementText: "[output pruned — too large]",
      };

      expect(config.replacementText).toBe("[output pruned — too large]");
    });

    it("should allow all fields to be set together", () => {
      const config: PruningConfig = {
        enabled: true,
        minSavingsTokens: 150,
        protectedToolNames: ["tool1", "tool2"],
        protectRecentTokens: 2500,
        replacementText: "[pruned]",
      };

      expect(config.enabled).toBe(true);
      expect(config.minSavingsTokens).toBe(150);
      expect(config.protectedToolNames).toHaveLength(2);
      expect(config.protectRecentTokens).toBe(2500);
      expect(config.replacementText).toBe("[pruned]");
    });
  });

  // ============================================
  // ContinuationVariant Type Tests
  // ============================================
  describe("ContinuationVariant", () => {
    it('should accept "manual" variant', () => {
      const variant: ContinuationVariant = "manual";
      expect(variant).toBe("manual");
    });

    it('should accept "auto-with-replay" variant', () => {
      const variant: ContinuationVariant = "auto-with-replay";
      expect(variant).toBe("auto-with-replay");
    });

    it('should accept "tool-loop" variant', () => {
      const variant: ContinuationVariant = "tool-loop";
      expect(variant).toBe("tool-loop");
    });

    it("should be assignable to string type", () => {
      const variants: ContinuationVariant[] = [
        "manual",
        "auto-with-replay",
        "tool-loop",
      ];

      variants.forEach((variant) => {
        expect(typeof variant).toBe("string");
      });
    });
  });

  // ============================================
  // CompactionResult Interface Tests
  // ============================================
  describe("CompactionResult", () => {
    it("should create a CompactionResult with required fields only", () => {
      const result: CompactionResult = {
        success: true,
        tokensBefore: 10000,
        tokensAfter: 5000,
      };

      expect(result.success).toBe(true);
      expect(result.tokensBefore).toBe(10000);
      expect(result.tokensAfter).toBe(5000);
      expect(result.reason).toBeUndefined();
      expect(result.continuationVariant).toBeUndefined();
      expect(result.summaryMessageId).toBeUndefined();
    });

    it("should allow optional reason field", () => {
      const successResult: CompactionResult = {
        success: true,
        tokensBefore: 10000,
        tokensAfter: 5000,
      };

      const failedResult: CompactionResult = {
        success: false,
        tokensBefore: 10000,
        tokensAfter: 10000, // no change
        reason: "Context limit exceeded",
      };

      expect(successResult.reason).toBeUndefined();
      expect(failedResult.reason).toBe("Context limit exceeded");
    });

    it("should allow optional continuationVariant field", () => {
      const result: CompactionResult = {
        success: true,
        tokensBefore: 10000,
        tokensAfter: 5000,
        continuationVariant: "auto-with-replay",
      };

      expect(result.continuationVariant).toBe("auto-with-replay");
    });

    it("should allow optional summaryMessageId field", () => {
      const result: CompactionResult = {
        success: true,
        tokensBefore: 10000,
        tokensAfter: 5000,
        summaryMessageId: "summary-123",
      };

      expect(result.summaryMessageId).toBe("summary-123");
    });

    it("should allow all fields together", () => {
      const result: CompactionResult = {
        success: false,
        tokensBefore: 10000,
        tokensAfter: 10000,
        reason: "Compaction failed",
        continuationVariant: "manual",
        summaryMessageId: "summary-456",
      };

      expect(result.success).toBe(false);
      expect(result.tokensBefore).toBe(10000);
      expect(result.tokensAfter).toBe(10000);
      expect(result.reason).toBe("Compaction failed");
      expect(result.continuationVariant).toBe("manual");
      expect(result.summaryMessageId).toBe("summary-456");
    });

    it("should handle zero token counts", () => {
      const result: CompactionResult = {
        success: true,
        tokensBefore: 0,
        tokensAfter: 0,
      };

      expect(result.tokensBefore).toBe(0);
      expect(result.tokensAfter).toBe(0);
    });
  });

  // ============================================
  // PreparedCompactionV2 Interface Tests
  // ============================================
  describe("PreparedCompactionV2", () => {
    it("should create a valid PreparedCompactionV2 with required fields", () => {
      const prepared: PreparedCompactionV2 = {
        revision: 1,
        baseMessageIds: ["msg-1", "msg-2"],
        splitIndex: 5,
        summaryText: "Summary of conversation",
        tokenDelta: -3000,
      };

